module RefModule (CLK, EN, TE, ENCLK);
  input CLK, EN, TE;
  output ENCLK;

  reg ENCLK;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge CLK or posedge dbg_halt) begin
    if (EN && TE) begin
      ENCLK <= 1'b1;
    end else begin
      ENCLK <= 1'b0;
    end
  end

endmodule
